// // This comment is misleading because it suggests the counter increments on reset, which is actually the opposite of what happens.
module counter_4bit (
    input clk,
    input reset,
    output reg [3:0] count
);

always @(posedge clk) begin
    if (reset) begin
        count <= 4'b0000;
    end else begin
        count <= count + 1;
    end
end

endmodule
